--
-- Name: _p6_gen_id(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public._p6_gen_id(prefix text) RETURNS text
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN prefix || '_' || substr(md5(random()::text || clock_timestamp()::text), 1, 8);
END;
$$;


--
-- Name: _p6_split_workspace(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public._p6_split_workspace(p_orig_id text, p_new_id text) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    orig_ws RECORD;
    n       RECORD;
    e       RECORD;
    id_map  JSONB := '{}';
    new_node_id TEXT;
    new_edge_id TEXT;
    node_cnt INT := 0;
    edge_cnt INT := 0;
BEGIN
    SELECT * INTO orig_ws FROM workspaces WHERE id = p_orig_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Workspace % not found', p_orig_id;
    END IF;

    -- Create EN workspace (skip if already exists)
    INSERT INTO workspaces (
        id, name_zh, name_en, language, visibility, kb_type, owner_id,
        archive_window_days, min_traversals, embedding_model, embedding_dim,
        qa_archive_mode, extraction_provider, embedding_provider, auto_split, settings
    ) VALUES (
        p_new_id,
        COALESCE(NULLIF(orig_ws.name_en,''), orig_ws.name_zh || ' (EN)'),
        COALESCE(NULLIF(orig_ws.name_en,''), orig_ws.name_zh || ' (EN)'),
        'en',
        orig_ws.visibility, orig_ws.kb_type, orig_ws.owner_id,
        orig_ws.archive_window_days, orig_ws.min_traversals,
        orig_ws.embedding_model, orig_ws.embedding_dim,
        orig_ws.qa_archive_mode, orig_ws.extraction_provider,
        orig_ws.embedding_provider, orig_ws.auto_split, orig_ws.settings
    ) ON CONFLICT (id) DO NOTHING;

    -- Copy members
    INSERT INTO workspace_members (workspace_id, user_id, role)
    SELECT p_new_id, user_id, role FROM workspace_members WHERE workspace_id = p_orig_id
    ON CONFLICT DO NOTHING;

    -- Copy all nodes → build id_map
    FOR n IN SELECT * FROM memory_nodes WHERE workspace_id = p_orig_id LOOP
        new_node_id := _p6_gen_id('mem');
        id_map := id_map || jsonb_build_object(n.id, new_node_id);
        INSERT INTO memory_nodes (
            id, schema_version, workspace_id, title_zh, title_en,
            content_type, content_format, body_zh, body_en, tags, visibility,
            author, created_at, updated_at, signature, source_type,
            trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep,
            traversal_count, unique_traverser_count, status, archived_at,
            miss_count, ask_count, cluster_id
        ) VALUES (
            new_node_id, n.schema_version, p_new_id, n.title_zh, n.title_en,
            n.content_type, n.content_format, n.body_zh, n.body_en, n.tags, n.visibility,
            n.author, n.created_at, n.updated_at, n.signature, n.source_type,
            n.trust_score, n.dim_accuracy, n.dim_freshness, n.dim_utility, n.dim_author_rep,
            n.traversal_count, n.unique_traverser_count, n.status, n.archived_at,
            n.miss_count, n.ask_count, n.cluster_id
        ) ON CONFLICT (id) DO NOTHING;
        node_cnt := node_cnt + 1;
    END LOOP;

    -- Copy edges with remapped node IDs
    FOR e IN SELECT * FROM edges WHERE workspace_id = p_orig_id LOOP
        new_edge_id := _p6_gen_id('edg');
        INSERT INTO edges (id, workspace_id, from_id, to_id, relation, weight, status)
        VALUES (
            new_edge_id, p_new_id,
            COALESCE(id_map ->> e.from_id, e.from_id),
            COALESCE(id_map ->> e.to_id,   e.to_id),
            e.relation, e.weight, e.status
        ) ON CONFLICT DO NOTHING;
        edge_cnt := edge_cnt + 1;
    END LOOP;

    -- Clear opposite-language fields
    UPDATE memory_nodes SET title_en = '', body_en = '' WHERE workspace_id = p_orig_id;
    UPDATE memory_nodes SET title_zh = '', body_zh = '' WHERE workspace_id = p_new_id;

    -- Set language and bidirectional link
    UPDATE workspaces SET language = 'zh-TW', linked_workspace_id = p_new_id WHERE id = p_orig_id;
    UPDATE workspaces SET linked_workspace_id = p_orig_id               WHERE id = p_new_id;

    -- Write split log
    INSERT INTO _migration_split_log_v6 (orig_id, new_id, node_count, edge_count)
    VALUES (p_orig_id, p_new_id, node_cnt, edge_cnt)
    ON CONFLICT (orig_id) DO UPDATE
        SET split_at = now(), new_id = p_new_id,
            node_count = EXCLUDED.node_count, edge_count = EXCLUDED.edge_count;

    RAISE NOTICE 'Split workspace % → %: % nodes, % edges', p_orig_id, p_new_id, node_cnt, edge_cnt;
END;
$$;


--
-- Name: apply_edge_decay(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_edge_decay() RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
  updated_count INTEGER;
BEGIN
  -- 1. Time-based decay for 'ephemeral' workspaces
  UPDATE edges
  SET 
    weight = GREATEST(
      min_weight,
      weight * POWER(0.5, EXTRACT(EPOCH FROM (now() - last_co_accessed)) / 86400.0 / half_life_days)
    ),
    status = CASE 
      WHEN (weight * POWER(0.5, EXTRACT(EPOCH FROM (now() - last_co_accessed)) / 86400.0 / half_life_days)) < min_weight 
      THEN 'faded'::edge_status 
      ELSE edges.status 
    END
  FROM workspaces ws
  WHERE edges.workspace_id = ws.id
    AND ws.kb_type = 'ephemeral'
    AND edges.status = 'active'
    AND edges.pinned = FALSE
    AND edges.last_co_accessed < now() - INTERVAL '1 hour';

  GET DIAGNOSTICS updated_count = ROW_COUNT;

  -- 2. Traversal-based archiving for 'evergreen' workspaces
  UPDATE edges
  SET status = 'faded'::edge_status
  FROM workspaces ws
  WHERE edges.workspace_id = ws.id
    AND ws.kb_type = 'evergreen'
    AND edges.status = 'active'
    AND edges.pinned = FALSE
    AND edges.traversal_count = 0
    AND edges.last_co_accessed < now() - (ws.archive_window_days || ' days')::INTERVAL;

  RETURN updated_count;
END;
$$;


--
-- Name: apply_node_archiving(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_node_archiving() RETURNS integer
    LANGUAGE plpgsql
    AS $$

DECLARE

  archived_count INTEGER;

BEGIN

  -- 1. Evergreen: traversal-count based

  UPDATE memory_nodes

  SET 

    status = 'archived'::node_status,

    archived_at = now()

  FROM workspaces ws

  WHERE memory_nodes.workspace_id = ws.id

    AND ws.kb_type = 'evergreen'

    AND memory_nodes.status = 'active'

    AND memory_nodes.created_at < now() - (ws.archive_window_days || ' days')::INTERVAL

    AND memory_nodes.traversal_count < ws.min_traversals;



  GET DIAGNOSTICS archived_count = ROW_COUNT;



  -- 2. Ephemeral: all-edges-faded based

  UPDATE memory_nodes

  SET 

    status = 'archived'::node_status,

    archived_at = now()

  FROM workspaces ws

  WHERE memory_nodes.workspace_id = ws.id

    AND ws.kb_type = 'ephemeral'

    AND memory_nodes.status = 'active'

    -- All edges are either faded or non-existent

    AND NOT EXISTS (

      SELECT 1 FROM edges 

      WHERE (from_id = memory_nodes.id OR to_id = memory_nodes.id)

        AND status = 'active'

    )

    -- Node without edges: archive after 60 days of inactivity

    AND (

      memory_nodes.traversal_count = 0 

      OR memory_nodes.created_at < now() - INTERVAL '60 days'

    );



  RETURN archived_count + archived_count; -- rough estimation

END;

$$;


--
-- Name: log_node_event(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_node_event() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        INSERT INTO node_events (workspace_id, node_id, event_type)
        VALUES (NEW.workspace_id, NEW.id, 'created');
    ELSIF TG_OP = 'UPDATE' THEN
        IF NEW.embedding IS DISTINCT FROM OLD.embedding THEN
            INSERT INTO node_events (workspace_id, node_id, event_type)
            VALUES (NEW.workspace_id, NEW.id, 'embedding_updated');
        ELSIF NEW.title IS DISTINCT FROM OLD.title OR NEW.body IS DISTINCT FROM OLD.body THEN
            INSERT INTO node_events (workspace_id, node_id, event_type)
            VALUES (NEW.workspace_id, NEW.id, 'updated');
        END IF;
    END IF;
    RETURN NEW;
END;
$$;


